// Apply env vars and defaults
for arg in &self.args {
    if !result.contains_key(&arg.name) {
        // Try env var first
        if let Some(ref env_name) = arg.env_var {
            if let Ok(val) = env::var(env_name) {
                result.insert(arg.name.clone(), val);
                continue;
            }
        }
        // Then try default
        if let Some(ref default) = arg.default {
            result.insert(arg.name.clone(), default.clone());
        } else if arg.required {
            return Err(format!("Missing required arg: --{}", arg.name));
        }
    }
}
